const input = $input.first().json;
const body = input.body || input;
const type = body.type || 'directive';
const AGENT_WORKFLOW_MAP = {
  'aidan': 'lRTWOdnwTl9S4uDz', 'scout': 'E42nCnCDMNyqXBUa',
  'jordan': 'GDEkrPv1ShL9biXJ', 'iris': 'VSMBeuQeSBUiETNf',
  'atlas': 'uWar6a3rBK9yUZHt', 'nova': 'SVzmB2AzqiyGtsJF', 'sage': 'Un0wx8dCSVcgvOv5'
};
const N8N_API_KEY = process.env.N8N_API_KEY;
const SUPABASE_URL = process.env.SUPABASE_URL;
const SUPABASE_KEY = process.env.SUPABASE_SERVICE_KEY;
const fs = require('fs');
const http = require('http');
const https = require('https');
const n8nGet = (path) => new Promise((resolve, reject) => {
  const opts = { hostname: 'host.docker.internal', port: 5678, path: '/api/v1/' + path, method: 'GET', headers: { 'X-N8N-API-KEY': N8N_API_KEY } };
  let b = ''; const req = http.request(opts, res => { res.on('data', c => b += c); res.on('end', () => resolve(JSON.parse(b || '{}'))); }); req.on('error', reject); req.end();
});
const n8nPut = (path, payload) => new Promise((resolve, reject) => {
  const bodyStr = JSON.stringify(payload);
  const opts = { hostname: 'host.docker.internal', port: 5678, path: '/api/v1/' + path, method: 'PUT', headers: { 'X-N8N-API-KEY': N8N_API_KEY, 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(bodyStr) } };
  let resp = ''; const req = http.request(opts, res => { res.on('data', c => resp += c); res.on('end', () => resolve({ status: res.statusCode })); }); req.on('error', reject); req.write(bodyStr); req.end();
});
const supabasePost = (table, payload) => new Promise((resolve, reject) => {
  const bodyStr = JSON.stringify(payload);
  const url = new URL(SUPABASE_URL + '/rest/v1/' + table);
  const opts = { hostname: url.hostname, path: url.pathname, method: 'POST', headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Content-Type': 'application/json', 'Prefer': 'return=minimal', 'Content-Length': Buffer.byteLength(bodyStr) } };
  const req = https.request(opts, res => { let d = ''; res.on('data', c => d += c); res.on('end', () => resolve({ status: res.statusCode })); }); req.on('error', reject); req.write(bodyStr); req.end();
});
const results = [];
if (type === 'directive' || type === 'directives') {
  const directives = body.directives || {};
  if (body.agent && body.directive) directives[body.agent] = body.directive;
  for (const [agentName, directiveText] of Object.entries(directives)) {
    const workflowId = AGENT_WORKFLOW_MAP[agentName.toLowerCase()];
    if (!workflowId || !directiveText) { results.push({ agent: agentName, status: 'skipped' }); continue; }
    try {
      const wf = await n8nGet('workflows/' + workflowId);
      if (!wf.nodes) { results.push({ agent: agentName, status: 'workflow not found' }); continue; }
      const targetNode = wf.nodes.find(n => n.type && (n.type.includes('Anthropic') || n.type.includes('anthropic') || n.type.includes('lmChat'))) ||
        wf.nodes.find(n => n.type === 'n8n-nodes-base.code' && (n.name.toLowerCase().includes('brain') || n.name.toLowerCase().includes('claude') || n.name.toLowerCase().includes('call')));
      if (!targetNode) { results.push({ agent: agentName, status: 'no Claude node found' }); continue; }
      if (targetNode.parameters?.options?.systemMessage !== undefined) {
        targetNode.parameters.options.systemMessage = directiveText;
      } else if (targetNode.parameters?.systemPromptTemplate !== undefined) {
        targetNode.parameters.systemPromptTemplate = directiveText;
      } else if (targetNode.parameters?.jsCode !== undefined) {
        const existing = targetNode.parameters.jsCode;
        const marker = '// [ECL-DIRECTIVE]';
        const markerEnd = '// [/ECL-DIRECTIVE]';
        const block = marker + '\n// ' + directiveText.replace(/\n/g,'\n// ') + '\n' + markerEnd + '\n';
        targetNode.parameters.jsCode = existing.includes(marker) ? existing.replace(new RegExp(marker + '[\\s\\S]*?' + markerEnd + '\\n'), block) : block + existing;
      }
      const pr = await n8nPut('workflows/' + workflowId, { name: wf.name, nodes: wf.nodes, connections: wf.connections, settings: wf.settings, staticData: wf.staticData });
      results.push({ agent: agentName, workflowId, nodeUpdated: targetNode.name, status: pr.status === 200 ? 'updated' : 'http_' + pr.status });
    } catch(e) { results.push({ agent: agentName, status: 'error: ' + e.message }); }
  }
}
if (type === 'deadlines') {
  try {
    const ctxPath = '/data/KAI_Context.json';
    const ctx = JSON.parse(fs.readFileSync(ctxPath, 'utf8'));
    const deadlines = body.deadlines || [];
    deadlines.forEach(dl => {
      const existing = ctx.deadlines?.find(d => d.item?.toLowerCase().includes((dl.id || dl.name || '').toLowerCase().substring(0,10)));
      if (existing) { if (dl.status) existing.status = dl.status; if (dl.date) existing.date = dl.date; if (dl.notes) existing.notes = dl.notes; }
    });
    ctx.meta.updated = new Date().toISOString().split('T')[0];
    fs.writeFileSync(ctxPath, JSON.stringify(ctx, null, 2));
    results.push({ type: 'deadlines', status: 'patched', count: deadlines.length });
  } catch(e) { results.push({ type: 'deadlines', status: 'error: ' + e.message }); }
}
if (type === 'context') {
  try {
    const ctxPath = '/data/KAI_Context.json';
    const ctx = JSON.parse(fs.readFileSync(ctxPath, 'utf8'));
    const merge = (t, s) => { for (const k of Object.keys(s)) { if (typeof s[k]==='object'&&!Array.isArray(s[k])&&t[k]) merge(t[k],s[k]); else t[k]=s[k]; } };
    merge(ctx, body.patch || {});
    ctx.meta.updated = new Date().toISOString().split('T')[0];
    fs.writeFileSync(ctxPath, JSON.stringify(ctx, null, 2));
    await supabasePost('agent_executions', { agent: 'Scribe', trigger_type: 'ecl_portal', status: 'success', notes: 'KAI_Context.json patched via ECL portal' });
    results.push({ type: 'context', status: 'patched' });
  } catch(e) { results.push({ type: 'context', status: 'error: ' + e.message }); }
}
if (type === 'bd') {
  let written = 0;
  for (const entry of (body.entries || [])) {
    try { await supabasePost('bd_pipeline', { organization: entry.org, opportunity: entry.opp, vertical: entry.vert, fit_score: parseInt(entry.fit)||null, stage: entry.stage, notes: entry.notes, source: 'ecl_portal' }); written++; } catch(e) {}
  }
  results.push({ type: 'bd', status: 'written', count: written });
}
return [{ json: { success: true, results, timestamp: new Date().toISOString() } }];
